"use client";

import { useEffect, useRef } from "react";
import {
  Application,
  Container,
  Graphics,
  Sprite,
  type Texture,
} from "pixi.js";

import type {
  StageDrawList,
  StageSpriteDraw,
} from "./draw-list";
import styles from "./PixiStage.module.css";
import {
  destroyStageTextures,
  ensureStageTextures,
  type StageTextureMap,
} from "./sprite-layer";

type PixiStageCanvasProps = {
  readonly drawList: StageDrawList;
};

const safelyDestroyApplication = (app: Application): void => {
  if (!app.renderer) {
    return;
  }

  try {
    app.destroy(true, { children: true });
  } catch {
    // Half-initialized Pixi apps may throw if ResizePlugin teardown is missing.
  }
};

export default function PixiStageCanvas({ drawList }: PixiStageCanvasProps) {
  const hostRef = useRef<HTMLDivElement>(null);
  const appRef = useRef<Application | null>(null);
  const worldRef = useRef<Container | null>(null);
  const texturesRef = useRef<StageTextureMap>(new Map());

  useEffect(() => {
    if (typeof window === "undefined") {
      return;
    }

    const host = hostRef.current;

    if (host === null) {
      return;
    }

    let cancelled = false;
    const app = new Application();
    appRef.current = app;

    void (async () => {
      await app.init({
        width: drawList.canvasWidth,
        height: drawList.canvasHeight,
        background: 0x030509,
        antialias: false,
        resolution: 1,
        autoDensity: true,
      });

      if (cancelled) {
        safelyDestroyApplication(app);
        return;
      }

      host.replaceChildren(app.canvas);
      const world = new Container();
      worldRef.current = world;
      app.stage.addChild(world);
      paintDrawList(world, texturesRef.current, drawList);
    })();

    return () => {
      cancelled = true;
      worldRef.current = null;
      destroyStageTextures(texturesRef.current);
      safelyDestroyApplication(app);
      appRef.current = null;
      host.replaceChildren();
    };
  }, []);

  useEffect(() => {
    const app = appRef.current;
    const world = worldRef.current;

    if (app === null || world === null) {
      return;
    }

    app.renderer.resize(drawList.canvasWidth, drawList.canvasHeight);
    paintDrawList(world, texturesRef.current, drawList);
  }, [drawList]);

  return (
    <div
      className={styles.canvasHost}
      ref={hostRef}
      data-testid="pixi-stage-canvas-host"
      aria-hidden="true"
    />
  );
}

const paintDrawList = (
  world: Container,
  textures: StageTextureMap,
  drawList: StageDrawList,
): void => {
  ensureStageTextures(drawList, textures);
  clearWorld(world);

  world.scale.set(drawList.camera.zoom);
  world.position.set(drawList.camera.transformX, drawList.camera.transformY);

  const terrainLayer = new Container();
  const wallOverlayLayer = new Graphics();
  const glowLayer = new Graphics();
  const entityLayer = new Container();
  const fogLayer = new Graphics();

  for (const sprite of drawList.sprites.filter(
    (entry) => entry.layer === "terrain",
  )) {
    terrainLayer.addChild(spriteForDraw(sprite, textures));
  }

  for (const overlay of drawList.tileOverlays) {
    wallOverlayLayer.rect(overlay.x, overlay.y, overlay.width, overlay.height);
    wallOverlayLayer.fill({
      color: overlay.fillColor,
      alpha: overlay.alpha,
    });
  }

  for (const glow of drawList.glows) {
    glowLayer.circle(glow.x, glow.y, glow.radius);
    glowLayer.fill({ color: glow.fillColor, alpha: glow.alpha });
  }

  for (const sprite of drawList.sprites.filter(
    (entry) => entry.layer === "entity",
  )) {
    entityLayer.addChild(spriteForDraw(sprite, textures));
  }

  for (const fog of drawList.fog) {
    if (fog.alpha <= 0) {
      continue;
    }

    fogLayer.rect(fog.x, fog.y, fog.width, fog.height);
    fogLayer.fill({ color: fog.fillColor, alpha: fog.alpha });
  }

  world.addChild(terrainLayer);
  world.addChild(wallOverlayLayer);
  world.addChild(glowLayer);
  world.addChild(entityLayer);
  world.addChild(fogLayer);
};

const spriteForDraw = (
  draw: StageSpriteDraw,
  textures: ReadonlyMap<string, Texture>,
): Sprite => {
  const texture = textures.get(draw.atlasKeyString);

  if (texture === undefined) {
    throw new Error(`missing texture for ${draw.atlasKeyString}`);
  }

  const sprite = new Sprite({ texture, roundPixels: true });
  sprite.x = draw.x;
  sprite.y = draw.y;
  sprite.width = draw.width;
  sprite.height = draw.height;
  sprite.alpha = draw.alpha;
  sprite.tint = draw.tint;

  return sprite;
};

const clearWorld = (world: Container): void => {
  const removed = world.removeChildren();

  for (const child of removed) {
    child.destroy({ children: true });
  }
};

export type StageCameraState = {
  readonly viewportWidth: number;
  readonly viewportHeight: number;
  readonly worldWidth: number;
  readonly worldHeight: number;
  readonly zoom: number;
  readonly scrollX: number;
  readonly scrollY: number;
  readonly targetScrollX: number;
  readonly targetScrollY: number;
  readonly transformX: number;
  readonly transformY: number;
};

export type StageCameraInput = {
  readonly worldWidth: number;
  readonly worldHeight: number;
  readonly viewportWidth?: number;
  readonly viewportHeight?: number;
  readonly cellSize: number;
  readonly targetX: number;
  readonly targetY: number;
  readonly previous?: StageCameraState;
  readonly zoom?: number;
  readonly lerp?: number;
};

export const DEFAULT_STAGE_VIEWPORT_WIDTH = 640;
export const DEFAULT_STAGE_VIEWPORT_HEIGHT = 416;

const TARGET_VISIBLE_COLUMNS = 16;
const TARGET_VISIBLE_ROWS = 10;
const MIN_ZOOM = 1;
const MAX_ZOOM = 2;
const DEFAULT_LERP = 0.35;

export const resolveStageCamera = (
  input: StageCameraInput,
): StageCameraState => {
  const viewportWidth = Math.max(
    1,
    input.viewportWidth ?? DEFAULT_STAGE_VIEWPORT_WIDTH,
  );
  const viewportHeight = Math.max(
    1,
    input.viewportHeight ?? DEFAULT_STAGE_VIEWPORT_HEIGHT,
  );
  const worldWidth = Math.max(1, input.worldWidth);
  const worldHeight = Math.max(1, input.worldHeight);
  const zoom = input.zoom ?? chooseZoom(viewportWidth, viewportHeight, input.cellSize);
  const viewportWorldWidth = viewportWidth / zoom;
  const viewportWorldHeight = viewportHeight / zoom;
  const maxScrollX = Math.max(0, worldWidth - viewportWorldWidth);
  const maxScrollY = Math.max(0, worldHeight - viewportWorldHeight);
  const targetScrollX = clamp(input.targetX - viewportWorldWidth / 2, 0, maxScrollX);
  const targetScrollY = clamp(input.targetY - viewportWorldHeight / 2, 0, maxScrollY);
  const lerpAmount = clamp(input.lerp ?? DEFAULT_LERP, 0, 1);
  const canLerp =
    input.previous !== undefined &&
    input.previous.worldWidth === worldWidth &&
    input.previous.worldHeight === worldHeight &&
    input.previous.viewportWidth === viewportWidth &&
    input.previous.viewportHeight === viewportHeight &&
    input.previous.zoom === zoom;
  const scrollX = canLerp
    ? clamp(lerp(input.previous.scrollX, targetScrollX, lerpAmount), 0, maxScrollX)
    : targetScrollX;
  const scrollY = canLerp
    ? clamp(lerp(input.previous.scrollY, targetScrollY, lerpAmount), 0, maxScrollY)
    : targetScrollY;
  const scaledWorldWidth = worldWidth * zoom;
  const scaledWorldHeight = worldHeight * zoom;

  return {
    viewportWidth,
    viewportHeight,
    worldWidth,
    worldHeight,
    zoom,
    scrollX,
    scrollY,
    targetScrollX,
    targetScrollY,
    transformX:
      scaledWorldWidth <= viewportWidth
        ? (viewportWidth - scaledWorldWidth) / 2
        : -scrollX * zoom,
    transformY:
      scaledWorldHeight <= viewportHeight
        ? (viewportHeight - scaledWorldHeight) / 2
        : -scrollY * zoom,
  };
};

const chooseZoom = (
  viewportWidth: number,
  viewportHeight: number,
  cellSize: number,
): number =>
  clamp(
    Math.min(
      viewportWidth / (TARGET_VISIBLE_COLUMNS * cellSize),
      viewportHeight / (TARGET_VISIBLE_ROWS * cellSize),
    ),
    MIN_ZOOM,
    MAX_ZOOM,
  );

const lerp = (from: number, to: number, amount: number): number =>
  from + (to - from) * amount;

const clamp = (value: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, value));

import { Texture } from "pixi.js";

import fallbackArtJson from "../../../content/art/fallback/index.json" with { type: "json" };
// eslint-disable-next-line no-restricted-imports -- Phase 66-71 brief requires building Pixi textures from the phase-65 atlas cache.
import {
  SpriteAtlasCache,
  type SpriteAtlasEntry,
} from "../../../src/art/atlas.js";
// eslint-disable-next-line no-restricted-imports -- Phase 66-71 brief requires consuming the curated phase-65 fallback art set.
import {
  fallbackSpriteById,
  parseFallbackSpriteSet,
} from "../../../src/art/fallback.js";

import type { StageDrawList } from "./draw-list";

export type StageTextureMap = Map<string, Texture>;

const parsedFallback = parseFallbackSpriteSet(fallbackArtJson);

if (!parsedFallback.ok) {
  throw new Error(
    `invalid fallback art set: ${parsedFallback.errors.join("; ")}`,
  );
}

const FALLBACK_SPRITE_SET = parsedFallback.spriteSet;

export const ensureStageTextures = (
  drawList: StageDrawList,
  textures: StageTextureMap,
): StageTextureMap => {
  const atlas = new SpriteAtlasCache();

  for (const sprite of drawList.sprites) {
    if (textures.has(sprite.atlasKeyString)) {
      continue;
    }

    const fallback = fallbackSpriteById(FALLBACK_SPRITE_SET, sprite.spriteId);
    const entry = atlas.set(sprite.atlasKey, fallback.manifest);
    textures.set(sprite.atlasKeyString, textureFromAtlasEntry(entry));
  }

  return textures;
};

export const destroyStageTextures = (textures: StageTextureMap): void => {
  for (const texture of textures.values()) {
    texture.destroy(true);
  }

  textures.clear();
};

const textureFromAtlasEntry = (entry: SpriteAtlasEntry): Texture => {
  const canvas = document.createElement("canvas");
  canvas.width = entry.raster.width;
  canvas.height = entry.raster.height;

  const context = canvas.getContext("2d");
  if (context === null) {
    throw new Error(`2D canvas unavailable for sprite ${entry.keyString}`);
  }

  context.imageSmoothingEnabled = false;
  const pixels = new Uint8ClampedArray(
    new ArrayBuffer(entry.raster.pixels.byteLength),
  );
  pixels.set(entry.raster.pixels);
  context.putImageData(new ImageData(pixels, entry.raster.width, entry.raster.height), 0, 0);

  const texture = Texture.from(canvas, true);
  texture.source.scaleMode = "nearest";
  texture.label = entry.keyString;

  return texture;
};

import type {
  GridCellView,
  GridViewModel,
} from "@/components/grid/model";

export type StageGridMetrics = {
  readonly cellSize: number;
  readonly gap: number;
  readonly padding: number;
};

export type StageCellBounds = {
  readonly x: number;
  readonly y: number;
  readonly width: number;
  readonly height: number;
};

export type StageTileOverlayKind = "wall-shadow" | "wall-edge";

export type StageTileOverlayDraw = StageCellBounds & {
  readonly key: string;
  readonly kind: StageTileOverlayKind;
  readonly fillColor: number;
  readonly alpha: number;
};

export type WallPresentation = {
  readonly mask: number;
  readonly tint: number;
  readonly overlays: readonly StageTileOverlayDraw[];
};

export const WALL_MASK = {
  north: 1,
  east: 2,
  south: 4,
  west: 8,
  northeast: 16,
  southeast: 32,
  southwest: 64,
  northwest: 128,
} as const;

const WALL_TINT_SOLID = 0xffffff;
const WALL_TINT_OPEN_SOUTH = 0xd8decb;
const WALL_TINT_OPEN_CORNER = 0xc4cbbb;

export const boundsForCell = (
  cell: Pick<GridCellView, "x" | "y">,
  metrics: StageGridMetrics,
): StageCellBounds => ({
  x: metrics.padding + cell.x * (metrics.cellSize + metrics.gap),
  y: metrics.padding + cell.y * (metrics.cellSize + metrics.gap),
  width: metrics.cellSize,
  height: metrics.cellSize,
});

export const wallPresentationForCell = (
  model: GridViewModel,
  cell: GridCellView,
  bounds: StageCellBounds,
): WallPresentation => {
  if (!isWall(cell)) {
    return { mask: 0, tint: WALL_TINT_SOLID, overlays: [] };
  }

  const mask = wallMaskForCell(model, cell.x, cell.y);
  const openSouth = (mask & WALL_MASK.south) === 0;
  const openEast = (mask & WALL_MASK.east) === 0;
  const openNorth = (mask & WALL_MASK.north) === 0;
  const openWest = (mask & WALL_MASK.west) === 0;
  const openCardinals = [openNorth, openEast, openSouth, openWest].filter(
    Boolean,
  ).length;
  const overlays: StageTileOverlayDraw[] = [];
  const edge = Math.max(2, Math.floor(bounds.width * 0.11));
  const drop = Math.max(3, Math.floor(bounds.width * 0.18));

  if (openSouth) {
    overlays.push({
      key: `${cell.key}:wall-shadow:south`,
      kind: "wall-shadow",
      x: bounds.x,
      y: bounds.y + bounds.height - edge,
      width: bounds.width,
      height: drop,
      fillColor: 0x020306,
      alpha: 0.32,
    });
  }

  if (openEast) {
    overlays.push({
      key: `${cell.key}:wall-shadow:east`,
      kind: "wall-shadow",
      x: bounds.x + bounds.width - edge,
      y: bounds.y + edge,
      width: drop,
      height: bounds.height - edge,
      fillColor: 0x020306,
      alpha: 0.2,
    });
  }

  if (openNorth) {
    overlays.push({
      key: `${cell.key}:wall-edge:north`,
      kind: "wall-edge",
      x: bounds.x,
      y: bounds.y,
      width: bounds.width,
      height: edge,
      fillColor: 0xf2f6dc,
      alpha: 0.16,
    });
  }

  if (openWest) {
    overlays.push({
      key: `${cell.key}:wall-edge:west`,
      kind: "wall-edge",
      x: bounds.x,
      y: bounds.y,
      width: edge,
      height: bounds.height,
      fillColor: 0xf2f6dc,
      alpha: 0.1,
    });
  }

  return {
    mask,
    tint:
      openCardinals >= 2
        ? WALL_TINT_OPEN_CORNER
        : openSouth
          ? WALL_TINT_OPEN_SOUTH
          : WALL_TINT_SOLID,
    overlays,
  };
};

export const wallMaskForCell = (
  model: GridViewModel,
  x: number,
  y: number,
): number => {
  let mask = 0;

  for (const neighbor of WALL_NEIGHBORS) {
    if (isWall(cellAt(model, x + neighbor.dx, y + neighbor.dy))) {
      mask |= neighbor.bit;
    }
  }

  return mask;
};

export const isWallTerrain = (terrain: string): boolean => terrain === "wall";

const isWall = (cell: GridCellView | undefined): boolean =>
  cell !== undefined && isWallTerrain(cell.terrain);

const cellAt = (
  model: GridViewModel,
  x: number,
  y: number,
): GridCellView | undefined => model.rows[y]?.[x];

const WALL_NEIGHBORS = [
  { dx: 0, dy: -1, bit: WALL_MASK.north },
  { dx: 1, dy: 0, bit: WALL_MASK.east },
  { dx: 0, dy: 1, bit: WALL_MASK.south },
  { dx: -1, dy: 0, bit: WALL_MASK.west },
  { dx: 1, dy: -1, bit: WALL_MASK.northeast },
  { dx: 1, dy: 1, bit: WALL_MASK.southeast },
  { dx: -1, dy: 1, bit: WALL_MASK.southwest },
  { dx: -1, dy: -1, bit: WALL_MASK.northwest },
] as const;

import type { GameState } from "@engine/state";

import type {
  GridCellView,
  GridViewModel,
} from "@/components/grid/model";

// eslint-disable-next-line no-restricted-imports -- Phase 66-71 brief requires the stage seam to consume the phase-65 art atlas.
import {
  FALLBACK_THEME_ID,
  spriteAtlasKey,
  serializeSpriteAtlasKey,
  type SpriteAtlasKey,
} from "../../../src/art/atlas.js";
// eslint-disable-next-line no-restricted-imports -- Phase 66-71 brief requires sprite ids from the phase-65 fallback art set.
import type { FallbackSpriteId } from "../../../src/art/fallback.js";
// eslint-disable-next-line no-restricted-imports -- Phase 66-71 brief requires the stage draw-list to resolve sprites through src/art.
import {
  resolveSpriteForCell,
  resolveTerrainSpriteId,
} from "../../../src/art/resolver.js";

import {
  DEFAULT_STAGE_VIEWPORT_HEIGHT,
  DEFAULT_STAGE_VIEWPORT_WIDTH,
  resolveStageCamera,
  type StageCameraState,
} from "./camera";
import {
  createFogDraws,
  fogPaintForCell,
  multiplyTint,
  type StageFogDraw,
} from "./fog";
import {
  boundsForCell,
  wallPresentationForCell,
  type StageGridMetrics,
  type StageTileOverlayDraw,
} from "./tilemap";

export type StageSpriteLayer = "terrain" | "entity";

export type StageSpriteDraw = {
  readonly key: string;
  readonly cellKey: string;
  readonly layer: StageSpriteLayer;
  readonly x: number;
  readonly y: number;
  readonly width: number;
  readonly height: number;
  readonly atlasKey: SpriteAtlasKey;
  readonly atlasKeyString: string;
  readonly spriteId: FallbackSpriteId;
  readonly reason: string;
  readonly alpha: number;
  readonly tint: number;
  readonly wallMask: number | null;
};

export type StageGlowDraw = {
  readonly key: string;
  readonly x: number;
  readonly y: number;
  readonly radius: number;
  readonly fillColor: number;
  readonly alpha: number;
};

export type StageSignatureHook = {
  readonly key: string;
  readonly cellKey: string;
  readonly featureId: string;
  readonly featureKind: string;
  readonly phase: "phase87-signature-invention";
};

export type StageDrawList = {
  readonly width: number;
  readonly height: number;
  readonly cellSize: number;
  readonly gap: number;
  readonly padding: number;
  readonly worldWidth: number;
  readonly worldHeight: number;
  readonly canvasWidth: number;
  readonly canvasHeight: number;
  readonly camera: StageCameraState;
  readonly sprites: readonly StageSpriteDraw[];
  readonly tileOverlays: readonly StageTileOverlayDraw[];
  readonly glows: readonly StageGlowDraw[];
  readonly fog: readonly StageFogDraw[];
  readonly signatureHooks: readonly StageSignatureHook[];
};

const DEFAULT_CELL_SIZE = 32;
const DEFAULT_GAP = 0;
const DEFAULT_PADDING = 0;
const ENTITY_INSET = 3;
const HOARD_SCALE = 1.25;

export type StageDrawListOptions = {
  readonly state: GameState;
  readonly cellSize?: number;
  readonly gap?: number;
  readonly padding?: number;
  readonly viewportWidth?: number;
  readonly viewportHeight?: number;
  readonly zoom?: number;
  readonly cameraLerp?: number;
  readonly previousCamera?: StageCameraState;
};

/**
 * Pure function of `GridViewModel` + `GameState` -> Pixi draw instructions.
 * It uses the phase-65 art resolver/atlas key helpers; the painter only turns
 * these instructions into textures and shapes.
 */
export const createStageDrawList = (
  model: GridViewModel,
  options: StageDrawListOptions,
): StageDrawList => {
  const cellSize = options.cellSize ?? DEFAULT_CELL_SIZE;
  const gap = options.gap ?? DEFAULT_GAP;
  const padding = options.padding ?? DEFAULT_PADDING;
  const metrics = { cellSize, gap, padding } satisfies StageGridMetrics;
  const worldWidth =
    padding * 2 + model.width * cellSize + Math.max(0, model.width - 1) * gap;
  const worldHeight =
    padding * 2 + model.height * cellSize + Math.max(0, model.height - 1) * gap;
  const sprites: StageSpriteDraw[] = [];
  const tileOverlays: StageTileOverlayDraw[] = [];
  const glows: StageGlowDraw[] = [];
  const signatureHooks: StageSignatureHook[] = [];
  const playerCell = playerCellForModel(model);
  const playerBounds = boundsForCell(playerCell, metrics);
  const camera = resolveStageCamera({
    worldWidth,
    worldHeight,
    viewportWidth: options.viewportWidth ?? DEFAULT_STAGE_VIEWPORT_WIDTH,
    viewportHeight: options.viewportHeight ?? DEFAULT_STAGE_VIEWPORT_HEIGHT,
    cellSize,
    targetX: playerBounds.x + playerBounds.width / 2,
    targetY: playerBounds.y + playerBounds.height / 2,
    previous: options.previousCamera,
    zoom: options.zoom,
    lerp: options.cameraLerp,
  });

  for (const cell of model.cells) {
    const bounds = boundsForCell(cell, metrics);
    const fogPaint = fogPaintForCell(
      cell.fog,
      Math.hypot(cell.x - playerCell.x, cell.y - playerCell.y),
      { band: options.state.run.band },
    );
    const wallPresentation = wallPresentationForCell(model, cell, bounds);
    const terrainSprite = terrainSpriteForCell(options.state, cell);
    sprites.push({
      key: `${cell.key}:terrain:${terrainSprite.spriteId}`,
      cellKey: cell.key,
      layer: "terrain",
      ...bounds,
      atlasKey: terrainSprite.atlasKey,
      atlasKeyString: serializeSpriteAtlasKey(terrainSprite.atlasKey),
      spriteId: terrainSprite.spriteId,
      reason: terrainSprite.reason,
      alpha: fogPaint.spriteAlpha,
      tint: multiplyTint(wallPresentation.tint, fogPaint.spriteTint),
      wallMask: wallPresentation.mask,
    });
    tileOverlays.push(...wallPresentation.overlays);

    const entitySprite = entitySpriteForCell(options.state, cell, bounds, fogPaint);
    if (entitySprite !== null) {
      sprites.push(entitySprite);

      if (entitySprite.spriteId === "feature.hoard") {
        glows.push(hoardGlowForCell(options.state, cell, bounds));
      }
    }

    if (cell.featureKind !== "" && cell.featureKind !== "hoard") {
      signatureHooks.push({
        key: `${cell.key}:signature-hook`,
        cellKey: cell.key,
        featureId: cell.featureId,
        featureKind: cell.featureKind,
        phase: "phase87-signature-invention",
      });
    }
  }

  return {
    width: model.width,
    height: model.height,
    cellSize,
    gap,
    padding,
    worldWidth,
    worldHeight,
    canvasWidth: camera.viewportWidth,
    canvasHeight: camera.viewportHeight,
    camera,
    sprites,
    tileOverlays,
    glows,
    fog: createFogDraws(model, metrics, playerCell, {
      band: options.state.run.band,
    }),
    signatureHooks,
  };
};

const terrainSpriteForCell = (
  state: GameState,
  cell: GridCellView,
): {
  readonly atlasKey: SpriteAtlasKey;
  readonly spriteId: FallbackSpriteId;
  readonly reason: string;
} => {
  const spriteId = resolveTerrainSpriteId(cell.terrain);
  const atlasKey = spriteAtlasKey(FALLBACK_THEME_ID, spriteId, state.run.seed);

  return {
    atlasKey,
    spriteId,
    reason: cell.layer === "empty" ? "grid.empty" : `terrain.${cell.terrain}`,
  };
};

const entitySpriteForCell = (
  state: GameState,
  cell: GridCellView,
  bounds: { readonly x: number; readonly y: number; readonly width: number; readonly height: number },
  fogPaint: ReturnType<typeof fogPaintForCell>,
): StageSpriteDraw | null => {
  if (!shouldDrawEntitySprite(cell)) {
    return null;
  }

  const resolved = resolveSpriteForCell(state, cell);
  const size =
    resolved.spriteId === "feature.hoard"
      ? bounds.width * HOARD_SCALE
      : bounds.width - ENTITY_INSET * 2;
  const x = bounds.x + (bounds.width - size) / 2;
  const y = bounds.y + (bounds.height - size) / 2;

  return {
    key: `${cell.key}:entity:${resolved.spriteId}`,
    cellKey: cell.key,
    layer: "entity",
    x,
    y,
    width: size,
    height: size,
    atlasKey: resolved.atlasKey,
    atlasKeyString: serializeSpriteAtlasKey(resolved.atlasKey),

import { createElement } from "react";
import { renderToStaticMarkup } from "react-dom/server";
import { describe, expect, it } from "vitest";

import {
  createFogMixGridFixtureState,
  createMidActionGridFixtureState,
  createPrecedenceFixtureState,
