const rowsForCells = (
  cells: readonly GridCellView[],
  width: number,
): readonly (readonly GridCellView[])[] => {
  if (width <= 0) {
    return [];
  }

  const rows: GridCellView[][] = [];

  for (let offset = 0; offset < cells.length; offset += width) {
    rows.push(cells.slice(offset, offset + width));
  }

  return rows;
};

