import type { GameConfig } from "../../config/index.js";
import type {
  DepthBand,
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  QuestDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { StatusApplication } from "../../schemas/vocab/index.js";

export type SerializablePrimitive = string | number | boolean | null;

export type SerializableValue =
  | SerializablePrimitive
  | readonly SerializableValue[]
  | { readonly [key: string]: SerializableValue };

export type SerializableRecord = {
  readonly [key: string]: SerializableValue;
};

export const ACTIVE_TERMINAL_STATUS = "ACTIVE" as const;

export type ConfiguredTerminalStatus =
  GameConfig["runStructure"]["terminalStates"][keyof GameConfig["runStructure"]["terminalStates"]];

export type TerminalStatus =
  | typeof ACTIVE_TERMINAL_STATUS
  | ConfiguredTerminalStatus;

export interface VersionStamp {
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: typeof ENGINE_VERSION;
}

export interface RunMeta {
  readonly runId: string;
  readonly seed: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly turn: number;
  readonly terminalStatus: TerminalStatus;
  readonly itemKnowledge: ItemKnowledgeState;
}

export interface ItemKnowledgeState {
  readonly identifiedDefinitionIds: readonly string[];
  readonly bonusRevealedItemInstanceIds: readonly string[];
  readonly chargesByItemInstanceId: {
    readonly [itemInstanceId: string]: number;
  };
}

export interface Position {
  readonly x: number;
  readonly y: number;
}

export interface FloorGeometrySlot {
  readonly refId: string;
  /*
   * PHASE-07A contract: the map module owns this payload's concrete shape.
   * PHASE-06 only requires a stable, serializable geometry reference by id.
   */
  readonly opaque: SerializableRecord | null;
}

export interface FloorState {
  readonly floorId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly geometry: FloorGeometrySlot;
}

export interface PlayerItemStack {
  readonly itemInstanceId: string;
  readonly definition: ItemDefinition;
  readonly quantity: number;
  readonly identified: boolean;
}

export type InventorySlot = PlayerItemStack | null;

export interface EquipmentState {
  readonly weapon: PlayerItemStack | null;
  readonly armor: PlayerItemStack | null;
  readonly charms: readonly (PlayerItemStack | null)[];
}

export interface PlayerState {
  readonly hp: {
    readonly current: number;
    readonly max: number;
  };
  readonly level: number;
  readonly xp: number;
  readonly fullness: {
    readonly current: number;
    readonly max: number;
  };
  readonly position: Position;
  readonly inventory: readonly InventorySlot[];
  readonly equipment: EquipmentState;
  readonly statuses: readonly StatusApplication[];
}

export type EntityKind = "enemy" | "npc" | "item" | "trap";

export type EntityIdCounters = {
  readonly [Kind in EntityKind]: number;
};

export type EntityId = `${EntityKind}#${number}`;

export interface EntityRuntimeFields {
  readonly id: EntityId;
  readonly position: Position;
  readonly currentHP: number | null;
  readonly statuses: readonly StatusApplication[];
  readonly behaviorRuntime: SerializableRecord;
}

export interface EnemyEntityInstance extends EntityRuntimeFields {
  readonly kind: "enemy";
  readonly definition: EnemyDefinition;
  readonly currentHP: number;
}

export interface NpcEntityInstance extends EntityRuntimeFields {
  readonly kind: "npc";
  readonly definition: NpcDefinition;
  readonly dialogueRuntime: SerializableRecord;
}

export interface GroundItemEntityInstance extends EntityRuntimeFields {
  readonly kind: "item";
  readonly definition: ItemDefinition;
  readonly currentHP: null;
  readonly quantity: number;
  readonly identified: boolean;
}

export interface TrapEntityInstance extends EntityRuntimeFields {
  readonly kind: "trap";
  readonly definition: TrapDefinition;
  readonly currentHP: null;
  readonly armed: boolean;
}

export type EntityInstance =
  | EnemyEntityInstance
  | NpcEntityInstance
  | GroundItemEntityInstance
  | TrapEntityInstance;

export type EntityMap = {
  readonly [id: string]: EntityInstance;
};

export type QuestRuntimeStatus = "available" | "active" | "completed" | "failed";

export interface QuestRuntime {
  readonly definition: QuestDefinition;
  readonly status: QuestRuntimeStatus;
  readonly progress: SerializableRecord;
}

export interface QuestState {
  readonly quests: {
    readonly [id: string]: QuestRuntime;
  };
  readonly activeQuestIds: readonly string[];
  readonly completedQuestIds: readonly string[];
  readonly failedQuestIds: readonly string[];
}

/*
 * Log extension pattern:
 * later engine systems add event types by declaration-merging this interface.
 * The runtime serializer validates the event envelope and serializable data.
 */
export interface EngineLogEventDataByType {
  readonly state_created: {
    readonly runId: string;
    readonly seed: string;
    readonly depth: number;
    readonly band: DepthBand;
  };
  readonly state_serialized: {
    readonly format: "stable-json";
  };
  readonly state_deserialized: {
    readonly format: "stable-json";
  };
}

export type EngineLogEventType = Extract<
  keyof EngineLogEventDataByType,
  string
>;

export type EngineLogEvent = {
  readonly [Type in EngineLogEventType]: {
    readonly turn: number;
    readonly type: Type;
    readonly data: EngineLogEventDataByType[Type];
  };
}[EngineLogEventType];

export interface RngStreamCursor {
  readonly streamId: string;
  readonly seed: string;
  readonly parentStreamId: string | null;
  readonly draws: number;
}

export interface RngState {
  readonly rootSeed: string;
  readonly streams: {
    readonly [streamId: string]: RngStreamCursor;
  };
}

export interface IdState {
  readonly entityCounters: EntityIdCounters;
}

export interface GameState {
  readonly version: VersionStamp;
  readonly run: RunMeta;
  readonly floor: FloorState;
  readonly player: PlayerState;
  readonly entities: EntityMap;
  readonly quests: QuestState;
  readonly log: readonly EngineLogEvent[];
  readonly rng: RngState;
  readonly ids: IdState;
}

  return fog.tiles.map((tile) => {
    switch (tile.state) {
      case "visible":
      case "remembered":
      case "unseen":
        return tile.state;
      default:
        return "unseen";
    }
  });
};

const effectsSinceLastRender = (
  state: GameState,
  previousCursor?: GridRenderCursor,
): ReadonlyMap<string, CellEffects> => {
  const cursor = cursorForState(state);
  const canDiff =
    previousCursor !== undefined &&
    previousCursor.runId === cursor.runId &&
    previousCursor.floorId === cursor.floorId &&
    previousCursor.logLength <= cursor.logLength;

  if (!canDiff) {
    return new Map();
  }

  const events = (state.log as readonly RuntimeLogEvent[]).slice(
    previousCursor.logLength,
  );

  if (events.length === 0) {
    return new Map();
  }

  const positionsByActorId = actorPositions(state);
  const effectsByPosition = new Map<string, MutableCellEffects>();

  events.forEach((event, eventIndex) => {
    applyPulseEvent(event, eventIndex, positionsByActorId, effectsByPosition);
    applyMovementEvent(event, positionsByActorId, effectsByPosition);
  });

  return new Map(
    [...effectsByPosition.entries()].map(([key, effects]) => [
      key,
      {
        pulses: effects.pulses,
        hitFlash: effects.hitFlash,
        motion: effects.motion,
      },
    ]),
  );
};

const applyPulseEvent = (
  event: RuntimeLogEvent,
  eventIndex: number,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  const data = asRecord(event.data);
  const eventId = `${String(event.turn ?? "t")}:${String(event.type)}:${eventIndex}`;

  switch (event.type) {
    case "attack_hit": {
      const defenderId = stringValue(data?.defenderId);
      const damage = numberValue(data?.damage);

      if (defenderId !== null && damage !== null && damage > 0) {
        addPulseForActor(
          defenderId,
          positionsByActorId,
          effectsByPosition,
          {
            id: eventId,
            kind: "damage",
            text: `-${damage}`,
          },
        );
      }
      break;
    }
    case "status_tick": {
      const entityId = stringValue(data?.entityId);
      const hpDelta = numberValue(data?.hpDelta);

      if (entityId !== null && hpDelta !== null && hpDelta !== 0) {
        addPulseForActor(
          entityId,
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpDelta),
        );
      }
      break;
    }
    case "starvation": {
      const hpBefore = numberValue(data?.hpBefore);
      const hpAfter = numberValue(data?.hpAfter);

      if (hpBefore !== null && hpAfter !== null && hpAfter !== hpBefore) {
        addPulseForActor(
          "player",
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
    case "level_up": {
      const hpBefore = numberValue(data?.currentHpBefore);
      const hpAfter = numberValue(data?.currentHpAfter);

      if (hpBefore !== null && hpAfter !== null && hpAfter !== hpBefore) {
        addPulseForActor(
          "player",
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
    case "effect_executed": {
      const verb = stringValue(data?.verb);
      const targetId = stringValue(data?.targetId);
      const details = asRecord(data?.details);
      const hpBefore = numberValue(details?.hpBefore);
      const hpAfter = numberValue(details?.hpAfter);

      if (
        targetId !== null &&
        hpBefore !== null &&
        hpAfter !== null &&
        hpAfter !== hpBefore &&
        (verb === "damage" || verb === "heal")
      ) {
        addPulseForActor(
          targetId,
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
  }
};

const applyMovementEvent = (
  event: RuntimeLogEvent,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  if (event.type !== "moved" && event.type !== "enemy_moved") {
    return;
  }

  const data = asRecord(event.data);
  const actorId = stringValue(data?.actorId);
  const from = positionValue(data?.from);
  const to = positionValue(data?.to) ?? (actorId === null
    ? null
    : positionsByActorId.get(actorId) ?? null);

  if (from === null || to === null) {
    return;
  }

  const effects = mutableEffectsAt(effectsByPosition, to);
  effects.motion = {
    dx: from.x - to.x,
    dy: from.y - to.y,
  };
};

const pulseForDelta = (id: string, delta: number): GridPulse => ({
  id,
  kind: delta < 0 ? "damage" : "heal",
  text: `${delta > 0 ? "+" : ""}${delta}`,
});

const addPulseForActor = (
  actorId: string,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
  pulse: GridPulse,
): void => {
  const position = positionsByActorId.get(actorId);

  if (position === undefined) {
    return;
  }

  const effects = mutableEffectsAt(effectsByPosition, position);
  effects.pulses.push(pulse);

  if (pulse.kind === "damage") {
    effects.hitFlash = true;

    effects.hitFlash = true;
  }
};

const mutableEffectsAt = (
  effectsByPosition: Map<string, MutableCellEffects>,
  position: Position,
): MutableCellEffects => {
  const key = keyForPosition(position);
  const existing = effectsByPosition.get(key);

  if (existing !== undefined) {
    return existing;
  }

  const created: MutableCellEffects = {
    pulses: [],
    hitFlash: false,
    motion: null,
  };
  effectsByPosition.set(key, created);

  return created;
};

const actorPositions = (state: GameState): ReadonlyMap<string, Position> => {
  const positions = new Map<string, Position>([["player", state.player.position]]);

  for (const entity of Object.values(state.entities)) {
    positions.set(entity.id, entity.position);
  }

  for (const event of state.log as readonly RuntimeLogEvent[]) {
    if (event.type !== "entity_died") {
      continue;
    }

    const data = asRecord(event.data);
    const entityId = stringValue(data?.entityId);
    const position = positionValue(data?.position);

    if (entityId !== null && position !== null && !positions.has(entityId)) {
      positions.set(entityId, position);
    }
  }

  return positions;
};

const asRecord = (value: unknown): RuntimeRecord | null =>
  value !== null && typeof value === "object"
    ? (value as RuntimeRecord)
    : null;

const numberValue = (value: unknown): number | null =>
  typeof value === "number" && Number.isFinite(value) ? value : null;

const stringValue = (value: unknown): string | null =>
  typeof value === "string" ? value : null;

const positionValue = (value: unknown): Position | null => {
  const record = asRecord(value);
  const x = numberValue(record?.x);
  const y = numberValue(record?.y);

  return x === null || y === null ? null : { x, y };
};

const keyForPosition = (position: Position): string =>
  `${position.x},${position.y}`;

const samePosition = (left: Position, right: Position): boolean =>
  left.x === right.x && left.y === right.y;

