  log: [
    ...state.log,
    {
      turn: state.run.turn + 1,
      type: "attack_hit",
      data: {
        actorId: "player",
        defenderId: "enemy#1",
        attackerAttack: 5,
        defenderDefense: 1,
        baseDamage: 4,
        damage: 3,
        hitRoll: 8,
        hitChancePercent: 95,
        varianceMultiplier: 1,
        defenderHpBefore: 6,
        defenderHpAfter: 3,
      },
    } as GameState["log"][number],
    {
      turn: state.run.turn + 1,
      type: "status_tick",
      data: {
        entityId: "player",
        status: "regen",
        hpDelta: 2,
      },
    } as GameState["log"][number],
  ],
});

