107	const useStageMotionPreference = (): StageMotionPreference => {
108	  const [preference, setPreference] = useState<StageMotionPreference>("full");
109	
110	  useEffect(() => {
111	    setPreference(stageMotionPreferenceFromWindow());
112	  }, []);
113	
114	  return preference;
