117	const stageMotionPreferenceFromWindow = (): StageMotionPreference => {
118	  const searchParams = new URLSearchParams(window.location?.search ?? "");
119	  const motion = searchParams.get("motion") ?? searchParams.get("stageMotion");
120	  const reducedMotion = searchParams.get("reducedMotion");
121	
122	  if (
123	    motion === "off" ||
124	    motion === "reduced" ||
125	    motion === "snap" ||
126	    reducedMotion === "1" ||
127	    reducedMotion === "true"
128	  ) {
129	    return "reduced";
130	  }
131	
132	  if (motion === "on" || motion === "full" || reducedMotion === "0") {
133	    return "full";
134	  }
135	
136	  return window.matchMedia?.("(prefers-reduced-motion: reduce)").matches === true
137	    ? "reduced"
138	    : "full";
139	};

