 55	export default function PixiStageCanvas({
 56	  drawList,
 57	  animationPlan,
 58	}: PixiStageCanvasProps) {
 59	  const hostRef = useRef<HTMLDivElement>(null);
 60	  const appRef = useRef<Application | null>(null);
 61	  const worldRef = useRef<Container | null>(null);
 62	  const texturesRef = useRef<StageTextureMap>(new Map());
 63	  const animationRef = useRef<StageAnimationRuntime>(
 64	    createAnimationRuntime(drawList, animationPlan),
 65	  );
 66	
 67	  useEffect(() => {
 68	    if (typeof window === "undefined") {
 69	      return;
 70	    }
 71	
 72	    const host = hostRef.current;
 73	
 74	    if (host === null) {
 75	      return;
 76	    }
 77	
 78	    let cancelled = false;
 79	    const app = new Application();
 80	    appRef.current = app;
 81	
 82	    void (async () => {
 83	      await app.init({
 84	        width: drawList.canvasWidth,
 85	        height: drawList.canvasHeight,
 86	        background: 0x030509,
 87	        antialias: false,
 88	        resolution: 1,
 89	        autoDensity: true,
 90	      });
 91	
 92	      if (cancelled) {
 93	        safelyDestroyApplication(app);
 94	        return;
 95	      }
 96	
 97	      host.replaceChildren(app.canvas);
 98	      const world = new Container();
 99	      worldRef.current = world;
100	      app.stage.addChild(world);
101	      paintAnimatedFrame(world, texturesRef.current, animationRef.current);
102	
103	      const tick = (ticker: { readonly deltaMS: number }) => {
104	        advanceAnimationRuntime(animationRef.current, ticker.deltaMS);
105	        paintAnimatedFrame(world, texturesRef.current, animationRef.current);
106	      };
107	
108	      app.ticker.add(tick);
109	    })();
110	
111	    return () => {
112	      cancelled = true;
113	      worldRef.current = null;
114	      destroyStageTextures(texturesRef.current);
115	      safelyDestroyApplication(app);
116	      appRef.current = null;
117	      host.replaceChildren();
118	    };
119	  }, []);
