121	  useEffect(() => {
122	    const app = appRef.current;
123	    const world = worldRef.current;
124	    const runtime = animationRef.current;
125	
126	    updateAnimationRuntime(runtime, drawList, animationPlan);
127	
128	    if (app === null || world === null) {
129	      return;
130	    }
131	
132	    app.renderer.resize(drawList.canvasWidth, drawList.canvasHeight);
133	    paintAnimatedFrame(world, texturesRef.current, runtime);
134	  }, [animationPlan, drawList]);
