467	const movementOffset = (
468	  draw: StageSpriteDraw,
469	  runtime: StageAnimationRuntime,
470	): { readonly x: number; readonly y: number } => {
471	  const active = findLast(runtime.moves, (move) => move.event.toCellKey === draw.cellKey);
472	
473	  if (active === undefined) {
474	    return { x: 0, y: 0 };
475	  }
476	
477	  const progress = easedProgress(active.elapsedMs, active.durationMs);
478	  const pitch = runtime.drawList.cellSize + runtime.drawList.gap;
479	
480	  return {
481	    x: (active.event.from.x - active.event.to.x) * pitch * (1 - progress),
