537	const screenShakeOffset = (
538	  runtime: StageAnimationRuntime,
539	): { readonly x: number; readonly y: number } => {
540	  let x = 0;
541	  let y = 0;
542	
543	  for (const hit of runtime.hits) {
544	    if (hit.shakeMs <= 0 || hit.elapsedMs >= hit.shakeMs) {
545	      continue;
546	    }
547	
548	    const progress = normalizedProgress(hit.elapsedMs, hit.shakeMs);
549	    const falloff = 1 - progress;
550	    const phase = (stableHash(hit.event.id) % 360) * (Math.PI / 180);
551	    x += Math.sin(hit.elapsedMs * 0.09 + phase) * hit.event.shakePx * falloff;
552	    y += Math.cos(hit.elapsedMs * 0.11 + phase) * hit.event.shakePx * falloff * 0.65;
553	  }
554	
555	  return { x, y };
