822	const findLast = <Value,>(
823	  values: readonly Value[],
824	  predicate: (value: Value) => boolean,
825	): Value | undefined => {
826	  for (let index = values.length - 1; index >= 0; index -= 1) {
827	    const value = values[index];
828	
829	    if (value !== undefined && predicate(value)) {
830	      return value;
831	    }
832	  }
833	
834	  return undefined;
835	};
