837	const stableHash = (value: string): number => {
838	  let hash = 2166136261;
839	
840	  for (let index = 0; index < value.length; index += 1) {
841	    hash ^= value.charCodeAt(index);
842	    hash = Math.imul(hash, 16777619);
843	  }
844	
845	  return hash >>> 0;
