848	const mixColor = (base: number, overlay: number, amount: number): number => {
849	  const clamped = clamp(amount, 0, 1);
850	  const inverse = 1 - clamped;
851	  const red = Math.round(((base >> 16) & 0xff) * inverse + ((overlay >> 16) & 0xff) * clamped);
852	  const green = Math.round(((base >> 8) & 0xff) * inverse + ((overlay >> 8) & 0xff) * clamped);
853	  const blue = Math.round((base & 0xff) * inverse + (overlay & 0xff) * clamped);
854	
855	  return (red << 16) | (green << 8) | blue;
856	};
